-- Fix RLS for likes table to allow owners to see likes on their listings/profiles\nDROP POLICY IF EXISTS " Users can view their own likes\ ON public.likes;\n\nCREATE POLICY \Users can view their own likes and likes on their content\ ON public.likes\nFOR SELECT\nUSING (\n auth.uid() = user_id\n OR (\n target_type = 'listing' AND EXISTS (\n SELECT 1 FROM public.listings WHERE id = target_id AND owner_id = auth.uid()\n )\n )\n OR (\n target_type = 'profile' AND target_id = auth.uid()\n )\n);